import { Platform } from 'react-native';

const API_URL = 'https://api.example.com';
const AUTH_TOKEN_KEY = '@authToken';

async function fetchWithAuth(url, method, data) {
  const token = await AsyncStorage.getItem(AUTH_TOKEN_KEY);
  if (!token) return Promise.reject('No authentication token found');

  const headers = { Authorization: `Bearer ${token}` };
  const options = { method, headers, body: JSON.stringify(data), mode: 'cors' };

  try {
    const response = await fetch(url, options);
    if (response.ok) return response.json();
    else throw new Error(response.statusText);
  } catch (error) {
    console.error('Error fetching data:', error);
    throw error;
  }
}

async function getUserProfile() {
  const url = `${API_URL}/user/profile`;
  try {
    const response = await fetchWithAuth(url, 'GET');
    return response;
  } catch (error) {
    console.error('Error fetching user profile:', error);
    throw error;
  }
}

async function updateUserData(data) {
  const url = `${API_URL}/user/update`;
  try {
    const response = await fetchWithAuth(url, 'POST', data);
    return response;
  } catch (error) {
    console.error('Error updating user data:', error);
    throw error;
  }
}

async function login(username, password) {
  const url = `${API_URL}/login`;
  try {
    const response = await fetch(url, { method: 'POST', body: JSON.stringify({ username, password }) });
    if (response.ok) {
      const token = await response.json();
      await AsyncStorage.setItem(AUTH_TOKEN_KEY, token);
      return token;
    } else throw new Error(response.statusText);
  } catch (error) {
    console.error('Error logging in:', error);
    throw error;
  }
}

async function logout() {
  try {
    await AsyncStorage.removeItem(AUTH_TOKEN_KEY);
    return true;
  } catch (error) {
    console.error('Error logging out:', error);
    throw error;
  }
}